// checkCache determines incremental mode and skip set.
// Returns (shouldReturnEarly, incremental, skipIDs).
func checkCache(con DB, fingerprint string, force bool) (bool, bool, map[string]struct{}, error) {
	allChunkRows, err := con.Execute("SELECT chunk_id FROM embeddings")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query embeddings: %w", err)
	}
	allChunkIDs := make(map[string]struct{})
	for _, row := range allChunkRows {
		allChunkIDs[row[0]] = struct{}{}
	}

	processedRows, err := con.Execute("SELECT DISTINCT chunk_id FROM chunk_entities")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query chunk_entities: %w", err)
	}
	processedIDs := make(map[string]struct{})
	for _, row := range processedRows {
		processedIDs[row[0]] = struct{}{}
	}

	cachedRow, err := con.ExecuteOne("SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", fingerprint)
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query ner_cache: %w", err)
	}
	configMatch := cachedRow != nil

	newChunkIDs := make(map[string]struct{})
	for id := range allChunkIDs {
		if _, found := processedIDs[id]; !found {
			newChunkIDs[id] = struct{}{}
		}
	}

	if force {
		return false, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) == 0 {
		return true, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) > 0 {
		return false, true, processedIDs, nil
	}
	return false, false, make(map[string]struct{}), nil
}

