// persistAssociations writes associations and entities to the DB.
// If not incremental, existing rows are cleared first.
func persistAssociations(con DB, data map[string]interface{}, entityMeta map[string]EntityMeta, incremental bool) error {
	if !incremental {
		if err := con.Execute("DELETE FROM chunk_entities"); err != nil {
			return fmt.Errorf("persistAssociations: delete chunk_entities: %w", err)
		}
		if err := con.Execute("DELETE FROM entities"); err != nil {
			return fmt.Errorf("persistAssociations: delete entities: %w", err)
		}
	}

	associations, _ := data["associations"].([]map[string]interface{})
	for _, a := range associations {
		chunkID, _ := a["chunk_id"].(string)
		entityID, _ := a["entity_id"].(string)
		frequency, _ := a["frequency"].(int)
		score, _ := a["score"].(float64)
		positions, _ := a["positions"].([]int)

		nsRow, err := con.ExecuteOne("SELECT namespace FROM embeddings WHERE chunk_id = ?", chunkID)
		if err != nil {
			return fmt.Errorf("persistAssociations: query namespace: %w", err)
		}
		var chunkNamespace *string
		if nsRow != nil {
			s, _ := nsRow[0].(string)
			chunkNamespace = &s
		}

		posJSON, err := json.Marshal(positions)
		if err != nil {
			return fmt.Errorf("persistAssociations: marshal positions: %w", err)
		}
		if err := con.Execute(
			"INSERT OR REPLACE INTO chunk_entities(chunk_id, entity_id, frequency, positions_json, score, namespace) VALUES (?,?,?,?,?,?)",
			chunkID, entityID, frequency, string(posJSON), score, chunkNamespace,
		); err != nil {
			return fmt.Errorf("persistAssociations: insert chunk_entity: %w", err)
		}

		name, displayName, entityType := entityID, entityID, "concept"
		if meta, ok := entityMeta[entityID]; ok {
			name = meta.Name
			displayName = meta.DisplayName
			entityType = meta.EntityType
		}
		if err := con.Execute(
			"INSERT OR IGNORE INTO entities(id, name, display_name, entity_type) VALUES (?,?,?,?)",
			entityID, name, displayName, entityType,
		); err != nil {
			return fmt.Errorf("persistAssociations: insert entity: %w", err)
		}

		alias := stripIDAlias(entityID)
		if alias != "" {
			if err := con.Execute(
				"INSERT OR IGNORE INTO entity_aliases(alias, entity_id, source) VALUES (?,?,?)",
				alias, entityID, "strip_suffix",
			); err != nil {
				return fmt.Errorf("persistAssociations: insert alias: %w", err)
			}
		}
	}
	return nil
}

