type ChunkPair struct {
	ChunkID string
	Chunk   DocumentChunk
}

// collectChunksToProcess filters allChunks to those whose computed IDs are absent from skipIDs.
func collectChunksToProcess(allChunks []DocumentChunk, skipIDs map[string]struct{}) []ChunkPair {
	var result []ChunkPair
	for _, c := range allChunks {
		embedContent := c.EmbeddingContent
		if embedContent == "" {
			embedContent = c.Content
		}
		cid := GenerateChunkID(c.DocumentName, c.ChunkIndex, embedContent)
		if _, skip := skipIDs[cid]; !skip {
			result = append(result, ChunkPair{ChunkID: cid, Chunk: c})
		}
	}
	return result
}

