// singularize returns the singular form of word, or the original if it is an acronym,
// in the exception list, already singular, or if the inflect engine is unavailable.
func singularize(word string, engine InflectEngine, exceptions map[string]struct{}) string {
	if len(word) == 0 {
		return word
	}
	if isAcronym(word) {
		return word
	}
	lower := strings.ToLower(word)
	if _, inExceptions := exceptions[lower]; inExceptions {
		return word
	}
	if engine == nil {
		return word
	}
	result, isSingular, err := engine.SingularNoun(word)
	if err != nil {
		return word
	}
	if !isSingular {
		return word
	}
	if len(word) > 0 && word[0] >= 'A' && word[0] <= 'Z' && !isAcronym(word) {
		if len(result) == 0 {
			return word
		}
		return strings.ToUpper(result[:1]) + result[1:]
	}
	return result
}

