// It strips leading/trailing symbols, collapses dotted acronyms, singularizes the head noun.
func NormalizeEntity(entity string, engine InflectEngine) string {
	if len(entity) == 0 {
		return ""
	}
	entity = strings.TrimSpace(entity)
	entity = leadingTrailingSymbols.ReplaceAllString(entity, "")
	entity = strings.TrimSpace(entity)

	parts := strings.Split(entity, " ")
	collapsed := make([]string, 0, len(parts))
	for _, tok := range parts {
		candidate := tok
		if !strings.HasSuffix(tok, ".") {
			candidate = tok + "."
		}
		if dottedAcronym.MatchString(candidate) {
			tok = strings.ReplaceAll(tok, ".", "")
		}
		collapsed = append(collapsed, tok)
	}
	entity = strings.Join(collapsed, " ")
	entity = multiSpace.ReplaceAllString(entity, " ")

	if len(entity) == 0 {
		return ""
	}

	tokens, sep := splitTokens(entity)
	var nonEmpty []string
	for _, t := range tokens {
		if len(t) > 0 {
			nonEmpty = append(nonEmpty, t)
		}
	}
	if len(nonEmpty) == 0 {
		return ""
	}
	nonEmpty[len(nonEmpty)-1] = singularize(nonEmpty[len(nonEmpty)-1], engine, singularExceptions)
	return strings.Join(nonEmpty, sep)
}

