// Match runs all enabled matchers and returns merged results.
// Priority: schema vocab = data vocab > spaCy.
func (p *NerPipeline) Match(text string) ([]EntityMatch, error) {
	var vocabHits []EntityMatch

	if p.dbEnrich {
		sm, err := p.getSchemaMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: schema matcher: %w", err)
		}
		hits, err := sm.Match(text)
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: schema match: %w", err)
		}
		vocabHits = append(vocabHits, hits...)
	}

	if p.builder.DataTermCount() > 0 {
		dm, err := p.getDataMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: data matcher: %w", err)
		}
		hits, err := dm.Match(text)
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: data match: %w", err)
		}
		vocabHits = append(vocabHits, hits...)
	}

	var spacyHits []EntityMatch
	if p.spacyEntities {
		sm, err := p.getSpacyMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: spacy matcher: %w", err)
		}
		spacyHits, err = sm.Match(text)
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: spacy match: %w", err)
		}
	}

	if len(vocabHits) > 0 && len(spacyHits) > 0 {
		return MergeMatches(vocabHits, spacyHits, text, true)
	}
	if len(vocabHits) > 0 {
		return vocabHits, nil
	}
	return spacyHits, nil
}

