// Normalize returns the canonical display form of entity using the instance exception list.
func (n *EntityNormalizer) Normalize(entity string) string {
	if len(entity) == 0 {
		return ""
	}
	entity = strings.TrimSpace(entity)
	entity = leadingTrailingSymbols.ReplaceAllString(entity, "")
	entity = strings.TrimSpace(entity)
	entity = multiSpace.ReplaceAllString(entity, " ")
	if len(entity) == 0 {
		return ""
	}
	tokens, sep := splitTokens(entity)
	var nonEmpty []string
	for _, t := range tokens {
		if len(t) > 0 {
			nonEmpty = append(nonEmpty, t)
		}
	}
	if len(nonEmpty) == 0 {
		return ""
	}
	last := nonEmpty[len(nonEmpty)-1]
	lower := strings.ToLower(last)
	if !isAcronym(last) {
		if _, inExceptions := n.exceptions[lower]; !inExceptions {
			if n.engine != nil {
				result, isSingular, err := n.engine.SingularNoun(last)
				if err == nil && isSingular {
					if len(last) > 0 && last[0] >= 'A' && last[0] <= 'Z' && !isAcronym(last) {
						if len(result) > 0 {
							result = strings.ToUpper(result[:1]) + result[1:]
						}
					}
					nonEmpty[len(nonEmpty)-1] = result
				}
			}
		}
	}
	return strings.Join(nonEmpty, sep)
}

// NerPipelineOptions holds configuration for a NerPipeline.
type NerPipelineOptions struct {
	DBEnrich             bool
	SpacyEntities        bool
	SpacyModel           string
	SpacyEntityTypes     []string
	MinSchemaTermLength  int
}

// NerPipeline is the unified NER pipeline: schema vocab + data vocab + spaCy, all merged.
type NerPipeline struct {
	dbEnrich         bool
	spacyEntities    bool
	spacyModel       string
	spacyEntityTypes []string
	builder          *SchemaVocabBuilder
	schemaMatcher    *SchemaMatcher
	dataMatcher      *VocabularyMatcher
	spacyMatcher     *SpacyMatcher
	schemaDirty      bool
	dataDirty        bool
}

// NewNerPipeline constructs a NerPipeline from the provided options.
func NewNerPipeline(opts NerPipelineOptions) (*NerPipeline, error) {
	model := opts.SpacyModel
	if model == "" {
		model = "en_core_web_sm"
	}
	minLen := opts.MinSchemaTermLength
	if minLen == 0 {
		minLen = 2
	}
	builder, err := NewSchemaVocabBuilder(minLen)
	if err != nil {
		return nil, fmt.Errorf("NewNerPipeline: builder init: %w", err)
	}
	return &NerPipeline{
		dbEnrich:         opts.DBEnrich,
		spacyEntities:    opts.SpacyEntities,
		spacyModel:       model,
		spacyEntityTypes: opts.SpacyEntityTypes,
		builder:          builder,
		schemaMatcher:    nil,
		dataMatcher:      nil,
		spacyMatcher:     nil,
		schemaDirty:      false,
		dataDirty:        false,
	}, nil
}
